"""Tests for skills/standards/scripts/applicability.sh.

The script depends on git remote (origin owner), HOME (standards dir path),
and the contents of ~/source/standards/CLAUDE.md. Tests mock these by:
- Creating a temp git repo with a controlled origin remote
- Setting HOME to a temp dir with a mock standards tree
- Providing minimal CLAUDE.md content
"""

import os
import subprocess
import sys
from pathlib import Path
from textwrap import dedent

import pytest

SCRIPT = (
    Path(__file__).resolve().parent.parent
    / "scripts"
    / "applicability.sh"
)


def _run(*, cwd: str, home: str, env_extra: dict | None = None) -> subprocess.CompletedProcess:
    env = {**os.environ, "HOME": home}
    if env_extra:
        env.update(env_extra)
    return subprocess.run(
        ["bash", str(SCRIPT)],
        cwd=cwd,
        env=env,
        capture_output=True,
        text=True,
    )


def _init_repo(tmp_path: Path, *, owner: str = "jewzaam") -> Path:
    """Create a bare git repo with a controlled origin remote."""
    repo = tmp_path / "repo"
    repo.mkdir()
    subprocess.run(
        ["git", "init", "--initial-branch=main"],
        cwd=str(repo),
        capture_output=True,
        check=True,
    )
    subprocess.run(
        ["git", "remote", "add", "origin", f"git@github.com:{owner}/test-repo.git"],
        cwd=str(repo),
        capture_output=True,
        check=True,
    )
    return repo


def _init_standards(tmp_path: Path, claude_md: str) -> Path:
    """Create a mock ~/source/standards/ tree."""
    home = tmp_path / "home"
    standards = home / "source" / "standards"
    standards.mkdir(parents=True)
    (standards / "CLAUDE.md").write_text(claude_md, encoding="utf-8")
    return home


class TestNotApplicable:
    def test_non_user_owner(self, tmp_path):
        repo = _init_repo(tmp_path, owner="someone-else")
        home = _init_standards(tmp_path, "## Common\n")
        result = _run(cwd=str(repo), home=str(home))
        assert result.returncode == 0
        assert "NOT_APPLICABLE" in result.stdout
