    def test_python_templates_merge_into_python(self, tmp_path):
        home = _init_standards(tmp_path, dedent("""\
            ## Python

            - [style](python/style.md) — style guide

            ## Python Templates

            - [Makefile](python/templates/Makefile) — template
        """))
        standards_dir = home / "source" / "standards"
        (standards_dir / "python").mkdir()
        (standards_dir / "python" / "style.md").write_text("# Style\n")
        (standards_dir / "python" / "templates").mkdir()
        (standards_dir / "python" / "templates" / "Makefile").write_text("all:\n")

        repo = _init_repo(tmp_path)
        result = _run(cwd=str(repo), home=str(home))
        lines = result.stdout.strip().split("\n")
        subdomains = [l for l in lines if l.startswith("SUBDOMAIN:")]
        assert len(subdomains) == 1
        assert subdomains[0] == "SUBDOMAIN: Python"
        file_lines = [l for l in lines if "FILE:" in l]
        assert len(file_lines) == 2

